INSERT INTO tiktok_conversion_logs (
  advertiser_id, pixel_id, event_type, event_id, user_id, click_id, external_id,
  event_value, currency, content_type, content_id,
  status, response_code, response_message, retry_count, event_time
) VALUES (
  #{advertiserId}, #{pixelId}, #{eventType}, #{eventId}, #{userId}, #{clickId}, #{externalId},
  #{eventValue}, COALESCE(#{currency}, 'USD'), #{contentType}, #{contentId},
  COALESCE(#{status}, 'pending'), #{responseCode}, #{responseMessage},
  COALESCE(#{retryCount}, 0), #{eventTime}
)

